const response = $input.first().json;

if (response.error) {
  throw new Error(`Gemini API error: ${response.error.code} — ${response.error.message}`);
}

const candidates = response.candidates;
if (!candidates || candidates.length === 0) {
  const blockReason = response.promptFeedback?.blockReason;
  throw new Error(`Gemini returned no candidates. Block reason: ${blockReason || 'unknown'}`);
}

const candidate = candidates[0];
const finishReason = candidate.finishReason;
if (finishReason && finishReason !== 'STOP' && finishReason !== 'MAX_TOKENS') {
  throw new Error(`Gemini stopped unexpectedly: finishReason=${finishReason}`);
}

const parts = candidate.content?.parts || [];
const rawText = parts.filter(p => p.text).map(p => p.text).join('').trim();

if (!rawText) {
  throw new Error('Gemini returned empty content.');
}

const cleaned = rawText
  .replace(/^```json\s*/i, '')
  .replace(/^```\s*/i, '')
  .replace(/\s*```$/i, '')
  .trim();

let digest;
try {
  digest = JSON.parse(cleaned);
} catch (e) {
  throw new Error(`Failed to parse Gemini JSON: ${e.message}. Raw: ${cleaned.substring(0, 500)}`);
}

if (!digest.stories || !Array.isArray(digest.stories)) {
  throw new Error('Invalid digest — missing stories array');
}

digest.stories.sort((a, b) => {
  if (a.importance === 'high' && b.importance !== 'high') return -1;
  if (b.importance === 'high' && a.importance !== 'high') return 1;
  return 0;
});

const groundingMeta = candidate.groundingMetadata;
if (groundingMeta?.webSearchQueries) {
  digest._searchQueries = groundingMeta.webSearchQueries;
}

return [{ json: digest }];

// LINK VALIDATOR v2
// For each story:
// 1. HEAD request on the original URL — if resolves, use it
// 2. If broken/null — call Gemini with Google Search to find the real URL
// 3. HEAD request on Gemini's result to confirm it works
// 4. If confirmed — use it
// 5. Last resort — Google search URL for the headline

const digest = $input.first().json;

const GOOGLE_SEARCH = (q) =>
  'https://www.google.com/search?q=' + encodeURIComponent(q);

const GEMINI_ENDPOINT =
  'https://generativelanguage.googleapis.com/v1beta/models/gemini-2.5-pro:generateContent';

// Check if a URL resolves with a 200-399 response
const checkUrl = async (url) => {
  if (!url || url === 'null' || url.includes('google.com/search')) return false;
  try {
    const res = await $helpers.request({
      method: 'HEAD',
      url,
      timeout: 7000,
      followRedirect: true,
      simple: false,
    });
    return res.statusCode >= 200 && res.statusCode < 400;
  } catch {
    return false;
  }
};

// Ask Gemini to find the correct direct URL for a headline + source
const findUrlWithGemini = async (headline, source, apiKey) => {
  try {
    const prompt = `Find the exact, direct URL for this specific article. Return ONLY the URL — no explanation, no markdown, no other text.

Article headline: "${headline}"
Published by: ${source}

Search for this article and return the full direct URL to it. If you cannot find a confirmed working direct URL, return the word null.`;

    const res = await $helpers.request({
      method: 'POST',
      url: `${GEMINI_ENDPOINT}?key=${apiKey}`,
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        contents: [{ role: 'user', parts: [{ text: prompt }] }],
        tools: [{ google_search: {} }],
        generationConfig: { temperature: 0, maxOutputTokens: 256 },
      }),
      timeout: 30000,
      simple: false,
    });

    const data = JSON.parse(res.body);
    const text = (data.candidates?.[0]?.content?.parts || [])
      .filter(p => p.text).map(p => p.text).join('').trim();

    // Extract URL from response
    const urlMatch = text.match(/https?:\/\/[^\s"'<>]+/);
    return urlMatch ? urlMatch[0].replace(/[.,;)]$/, '') : null;
  } catch {
    return null;
  }
};

// Get API key from credential
const apiKey = '{{ $credentials.googleGeminiApi.apiKey }}';

const validatedStories = [];
let stats = { ok: 0, fixed: 0, fallback: 0 };

for (const story of digest.stories) {
  // Step 1: check original URL
  const originalOk = await checkUrl(story.sourceUrl);

  if (originalOk) {
    stats.ok++;
    validatedStories.push(story);
    continue;
  }

  // Step 2: ask Gemini to find the real URL
  console.log(`[LINK VALIDATOR] Broken URL for "${story.headline}" — searching for correct link`);
  const foundUrl = await findUrlWithGemini(story.headline, story.source, apiKey);

  if (foundUrl) {
    // Step 3: confirm the found URL actually works
    const foundOk = await checkUrl(foundUrl);

    if (foundOk) {
      stats.fixed++;
      console.log(`[LINK VALIDATOR] Fixed: ${story.source} — "${story.headline}" → ${foundUrl}`);
      validatedStories.push({ ...story, sourceUrl: foundUrl, _urlFixed: true });
      continue;
    }
  }

  // Step 4: last resort — Google search
  stats.fallback++;
  console.warn(`[LINK VALIDATOR] Fallback to Google search: "${story.headline}"`);
  validatedStories.push({
    ...story,
    sourceUrl: GOOGLE_SEARCH(`${story.headline} ${story.source}`),
    _urlFallback: true,
  });
}

digest.stories = validatedStories;
digest._linkValidation = {
  ok: stats.ok,
  fixed: stats.fixed,
  fallback: stats.fallback,
  total: digest.stories.length,
};

console.log(`[LINK VALIDATOR] ${stats.ok} OK, ${stats.fixed} fixed via Gemini search, ${stats.fallback} fell back to Google search`);

return [{ json: digest }];

// PLAGIARISM CHECK NODE
// Checks summaries, keyPoints, effects, and realtorSection (NOT headlines)
// against open-access source articles for 8+ word verbatim matches.
// If flagged stories are found, passes them to the Rewrite Agent node.
// If clean, passes directly to Build HTML Email.

const digest = $input.first().json;

const OPEN_ACCESS_DOMAINS = [
  'federalreserve.gov',
  'consumerfinance.gov',
  'freddiemac.com',
  'fanniemae.com',
  'bls.gov',
  'census.gov',
  'conference-board.org',
  'nahb.org',
  'mba.org',
];

const isOpenAccess = (url) => {
  if (!url) return false;
  try {
    const hostname = new URL(url).hostname.replace('www.', '');
    return OPEN_ACCESS_DOMAINS.some(domain => hostname.includes(domain));
  } catch { return false; }
};

const fetchArticleText = async (url) => {
  try {
    const res = await $helpers.request({
      method: 'GET', url, timeout: 8000, simple: false,
      headers: { 'User-Agent': 'Mozilla/5.0 (compatible; DigestBot/1.0)' },
    });
    if (res.statusCode !== 200) return null;
    return res.body
      .replace(/<script[\s\S]*?<\/script>/gi, '')
      .replace(/<style[\s\S]*?<\/style>/gi, '')
      .replace(/<[^>]+>/g, ' ')
      .replace(/\s+/g, ' ')
      .trim()
      .toLowerCase();
  } catch { return null; }
};

const getNgrams = (text, n) => {
  const words = text.toLowerCase().replace(/[^a-z0-9\s]/g, '').split(/\s+/).filter(Boolean);
  const grams = new Set();
  for (let i = 0; i <= words.length - n; i++) {
    grams.add(words.slice(i, i + n).join(' '));
  }
  return grams;
};

// Only check these fields — headline is always excluded
const getCheckableText = (story) => {
  const parts = [];
  if (story.summary) parts.push(story.summary);
  if (story.keyPoints?.length) parts.push(...story.keyPoints);
  if (story.effects?.hasEffects) {
    if (story.effects.firstOrder?.length) parts.push(...story.effects.firstOrder);
    if (story.effects.secondOrder?.length) parts.push(...story.effects.secondOrder);
  }
  if (story.realtorSection?.hasRealtorAngle) {
    if (story.realtorSection.summary) parts.push(story.realtorSection.summary);
    if (story.realtorSection.actionables?.length) parts.push(...story.realtorSection.actionables);
  }
  return parts.join(' ');
};

const MIN_NGRAM = 8;
const flaggedStories = [];
const cleanStories = [];
let checked = 0;
let skipped = 0;

for (const story of digest.stories) {
  if (!isOpenAccess(story.sourceUrl)) {
    skipped++;
    cleanStories.push(story);
    continue;
  }

  const articleText = await fetchArticleText(story.sourceUrl);
  if (!articleText) {
    skipped++;
    cleanStories.push(story);
    continue;
  }

  checked++;
  const articleNgrams = getNgrams(articleText, MIN_NGRAM);
  const digestText = getCheckableText(story);
  const digestNgrams = getNgrams(digestText, MIN_NGRAM);
  const matches = [...digestNgrams].filter(gram => articleNgrams.has(gram));

  if (matches.length > 0) {
    flaggedStories.push({
      ...story,
      _plagiarismMatches: matches.slice(0, 5),
      _matchCount: matches.length,
    });
    console.warn(`[PLAGIARISM FLAGGED] "${story.headline}" — ${matches.length} match(es)`);
  } else {
    cleanStories.push(story);
  }
}

console.log(`[PLAGIARISM CHECK] ${checked} checked, ${skipped} skipped, ${flaggedStories.length} flagged`);

return [{ json: {
  ...digest,
  stories: cleanStories,        // clean stories pass through as-is
  _flaggedStories: flaggedStories, // flagged stories go to rewrite agent
  _plagiarismSummary: {
    checked, skipped,
    flagged: flaggedStories.length,
    needsRewrite: flaggedStories.length > 0,
  },
}}];

// REWRITE AGENT NODE
// Receives flagged stories from the Plagiarism Check node.
// Rewrites only the flagged fields (summary, keyPoints, effects, realtorSection)
// for each flagged story using Gemini — headlines, sources, and URLs are preserved.
// Merges rewritten stories back into the digest and passes everything to Build HTML Email.
// This is Option B: always send after rewrite regardless of second-check result.

const digest = $input.first().json;
const flaggedStories = digest._flaggedStories || [];

// If nothing was flagged, pass straight through
if (flaggedStories.length === 0) {
  console.log('[REWRITE AGENT] No flagged stories — passing through');
  const { _flaggedStories, _plagiarismSummary, ...cleanDigest } = digest;
  return [{ json: cleanDigest }];
}

console.log(`[REWRITE AGENT] Rewriting ${flaggedStories.length} flagged story/stories`);

const rewrittenStories = [];

for (const story of flaggedStories) {
  const { _plagiarismMatches, _matchCount, ...storyData } = story;

  const prompt = `You are a mortgage industry analyst. The following story summary contains text that too closely matches the source article. Rewrite ONLY the fields listed below using entirely original language. Do not copy any phrase from the source. Do not quote the article. Paraphrase all facts from scratch using different words and sentence structures.

PRESERVE EXACTLY (do not change):
- headline: "${storyData.headline}"
- source: "${storyData.source}"
- sourceUrl: "${storyData.sourceUrl}"
- importance: "${storyData.importance}"
- category: "${storyData.category}"

REWRITE THESE FIELDS using completely original language:
- summary (MAX 2 sentences, lead with key fact or number)
- keyPoints (MAX 3 bullets, MAX 10 words each, facts only)
- effects.firstOrder (MAX 2 items, MAX 12 words each) — only if hasEffects is true
- effects.secondOrder (MAX 2 items, MAX 12 words each) — only if hasEffects is true
- realtorSection.summary (MAX 2 sentences) — only if hasRealtorAngle is true
- realtorSection.actionables (MAX 2 items, MAX 12 words each) — only if hasRealtorAngle is true

Current content to rewrite:
${JSON.stringify(storyData, null, 2)}

Return ONLY valid JSON for this single story with all original fields preserved and the above fields rewritten. No markdown, no code fences, no commentary.`;

  try {
    const response = await $helpers.request({
      method: 'POST',
      url: `https://generativelanguage.googleapis.com/v1beta/models/gemini-2.5-pro:generateContent?key={{ $credentials.googleGeminiApi.apiKey }}`,
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        contents: [{ role: 'user', parts: [{ text: prompt }] }],
        generationConfig: { temperature: 0.4, maxOutputTokens: 1024 },
      }),
      timeout: 60000,
      simple: false,
    });

    const data = JSON.parse(response.body);
    const rawText = (data.candidates?.[0]?.content?.parts || [])
      .filter(p => p.text).map(p => p.text).join('').trim()
      .replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '');

    const rewritten = JSON.parse(rawText);

    // Enforce: headline, source, sourceUrl must not change
    rewritten.headline = storyData.headline;
    rewritten.source = storyData.source;
    rewritten.sourceUrl = storyData.sourceUrl;
    rewritten.importance = storyData.importance;
    rewritten.category = storyData.category;
    rewritten._rewritten = true;

    rewrittenStories.push(rewritten);
    console.log(`[REWRITE AGENT] Rewrote: "${storyData.headline}"`);
  } catch (err) {
    // If rewrite fails, include original story with a flag rather than drop it
    console.error(`[REWRITE AGENT] Failed to rewrite "${storyData.headline}": ${err.message}`);
    rewrittenStories.push({ ...storyData, _rewriteFailed: true });
  }
}

// Merge: clean stories + rewritten stories, restore original sort order
const allStories = [
  ...digest.stories,       // already-clean stories
  ...rewrittenStories,     // rewritten flagged stories
].sort((a, b) => {
  if (a.importance === 'high' && b.importance !== 'high') return -1;
  if (b.importance === 'high' && a.importance !== 'high') return 1;
  return 0;
});

// Strip internal fields before passing to email builder
const { _flaggedStories, _plagiarismSummary, ...finalDigest } = digest;
finalDigest.stories = allStories;
finalDigest._rewriteLog = {
  rewritten: rewrittenStories.length,
  rewriteFailed: rewrittenStories.filter(s => s._rewriteFailed).length,
};

console.log(`[REWRITE AGENT] Complete — ${rewrittenStories.length} rewritten, merging into digest`);

return [{ json: finalDigest }];

const body = $input.first().json.body || $input.first().json;

const email = (body.email || '').toLowerCase().trim();
const firstName = (body.firstName || '').trim();
const lastName = (body.lastName || '').trim();
const company = (body.company || '').trim();
const role = (body.role || '').trim();
const roleOther = (body.roleOther || '').trim();
const phone = (body.phone || '').trim();

// Required field validation
if (!email || !/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email)) {
  return [{ json: { valid: false, error: 'Valid email address is required.' } }];
}
if (!firstName) {
  return [{ json: { valid: false, error: 'First name is required.' } }];
}
if (!lastName) {
  return [{ json: { valid: false, error: 'Last name is required.' } }];
}
if (!role) {
  return [{ json: { valid: false, error: 'Please select your role.' } }];
}

return [{ json: {
  valid: true,
  email,
  firstName,
  lastName,
  fullName: `${firstName} ${lastName}`,
  company,
  role,
  roleOther,
  phone,
  subscribedAt: new Date().toISOString(),
  active: true,
  send_count: 0,
  last_sent_at: '',
  source: 'landing_page'
} }];

// Pick the row with the most recent timestamp from the Digest tab
const rows = $input.all().map(item => item.json);

if (!rows || rows.length === 0) {
  // No digest stored yet — skip the immediate send
  return [{ json: { hasDigest: false } }];
}

// Sort by timestamp descending, take the first
const sorted = rows.sort((a, b) => {
  return new Date(b.timestamp) - new Date(a.timestamp);
});

const latest = sorted[0];

if (!latest.html || !latest.subject) {
  return [{ json: { hasDigest: false } }];
}

return [{ json: {
  hasDigest: true,
  subject: latest.subject,
  html: latest.html,
  timestamp: latest.timestamp,
} }];
